var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"앗, 저기 있어요!","JPN":"あっ！　あそこにいます！","ENG":"Oh! They're over there!","TWN":"喔，在那！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"이번 임무는 철저히 변수를 제외하며 준비했다.","JPN":"今回の任務は徹底的に不確定要素の排除を行ってきた。","ENG":"We've prepared this operation meticulously by excluding all variables.","TWN":"這次任務我們徹底排除了所有變數。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"다방면으로 분석하고, 모든 경우의 수를 계산했어.","JPN":"あらゆる角度から分析し、あらゆる可能性を想定した。","ENG":"We analyzed it in many ways, and even calculated all the possible cases.","TWN":"全方面地分析了所有情況。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"가장 성공률이 높은 경로에 함선을 배치하고 적의 후방을 노렸다.","JPN":"最も成功率の高いルートに艦船を配備し、敵の後方を狙ったはずだ。","ENG":"We deployed ships where the success rates were the highest and aimed at the enemy's rear.","TWN":"甚至將艦船部署在成功率最高的路線上，瞄準了敵人的後方。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"하지만 어째서 이런 일이 발생한 거지?","JPN":"なのに、どうしてこんなことになってしまった？","ENG":"But how did this happen?","TWN":"但為什麼會發生這種事？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"분명 테라브레인의 예측에는 문제가 없었다.","JPN":"テラブレインの予測に問題点はなかった。","ENG":"There definitely weren't any issues with Terrabrain's predictions.","TWN":"顯然特拉大腦的預測沒有問題。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우리도 그 예측을 검토할 시간은 충분했어.","JPN":"我々にも、予測内容を検討する時間が十分にあった。","ENG":"There was plenty of time for us to review the predictions.","TWN":"我們也有足夠的時間來評估那個預測。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"그렇다면 무언가 개입해 변수를 만든 것이 틀림없다.","JPN":"だとすると、何かの介入によって想定外の状況が発生したと考えるしかない。","ENG":"Which leaves us with that someone must have intervened to create a variable.","TWN":"那麼，肯定是有什麼東西介入，製造了變數。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"도대체 누가…….","JPN":"いったい誰が……","ENG":"But who...?","TWN":"到底是誰……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>저 자는 마귀 우두머리의 힘을 빌리지 않고서는 마귀들을 쫓아내지 못한다</color>","JPN":"<color=#ff3636>あの者は魔物の長の手を借りずして、魔物を追い払うことができない。</color>","ENG":"<color=#ff3636>He cannot drive out the demons without borrowing the power of the demon leader.</color>","TWN":"<color=#ff3636>想要驅逐魔鬼，必向魔鬼之主發出乞求。</color>"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>어리석은 자들은 세상의 흐름을 보지 못하느니.</color>","JPN":"<color=#ff3636>愚か者たちは、世界の姿を正しく見ることができない。</color>","ENG":"<color=#ff3636>The foolish do not see the flow of the world.</color>","TWN":"<color=#ff3636>愚蠢之人看不見世界的流向。</color>"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>우리는 모두 그분의 겹눈이 되어 관조자의 눈으로 세상을 바라본다.</color>","JPN":"<color=#ff3636>我々は皆、あのお方の複眼となり、観照者として世界を眺めるのだ。</color>","ENG":"<color=#ff3636>We all become our Master's compound eyes and see the world with the eyes of an observer.</color>","TWN":"<color=#ff3636>我們成為祂的複眼，用觀照者的眼睛洞察世界。</color>"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>그것이 위대한 분의 뜻대로 세상을 정화하는 길.</color>\xA0","JPN":"<color=#ff3636>それが、あのお方のお心のままに、世界を浄化させる術。</color>\xA0","ENG":"<color=#ff3636>For that is the path to purify the world according to the great one.</color>\xA0","TWN":"<color=#ff3636>那是按照偉大之人的意願淨化世界的道路。</color>\xA0"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"현재 통신 장비를 포함한 모든 전자 장비는 정보 오염이 진행됐을 가능성이 높다.","JPN":"現在、通信設備などのあらゆる電子系の装備は、情報汚染に侵された可能性が高い。","ENG":"It is highly likely that all our electronics, including our comms, have been infected with the data corruption.","TWN":"目前包括通訊在內的所有電子設備都有可能已經遭受資訊污染。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"모두 주의하도록.","JPN":"全員、十分気を付けるように。","ENG":"Everyone, be cautious.","TWN":"請大家注意。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"내가 모두를 죽인 거야. 내 안일함이…… 내 잘못된 판단 한 번으로 모두가……!","JPN":"私が殺してしまった。私の甘さが……私の間違った判断が……皆を……！","ENG":"I killed them all. My carelessness... Just one wrong call, and everyone...!","TWN":"是我害死了所有人。因為我的疏忽……因為我一次錯誤的判斷……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"작전을 위해 모든 가능성을 살펴봤잖아, 이건 연산을 뛰어넘는 존재의 개입이 있다는 거야.\xA0","JPN":"作戦にあたって、あらゆる可能性を考慮していたはずだ。これは演算でも捉えきれない存在からの介入があったとしか言いようがない。\xA0","ENG":"We looked into all the possible outcomes for this operation. This must mean that there was an intervention from an entity beyond the calculation.\xA0","TWN":"我們已經考慮了所有的可能性。這只能說明有超越我們計算的存在介入。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"아마 이 의식은 그런 존재를 불러오는 것일지도 모르지.","JPN":"おそらく、この儀式はその存在を呼び込むためのものかもな。","ENG":"Perhaps this ritual is to summon such a being.","TWN":"也許這個儀式就是為了召喚那個東西。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_RED","text":{"KOREA":"여기서 주저앉아 있을 시간이 없다. 아디트야. 우린 나아가야 해.","JPN":"こんな場所でうなだれている暇はないぞ、アーディティヤ。俺たちは突き進まなければならない。","ENG":"There's no time to waste. Aditya. We must move forward.","TWN":"我們沒時間在這裡浪費，阿迪亞。我們必須前進。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"……젠장.","JPN":"……くそ。","ENG":"...Dammit.","TWN":"……可惡。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"우선 후발대로 오게 될지도 모를 아군에게 전달할 정보를 취합한다.","JPN":"では、ここに来るかもしれない支援部隊に伝えるための情報を整理する。","ENG":"First, let's gather information to pass on to allies who may arrive later.","TWN":"雖然不知道會不會有後援，但就先收集好需要傳達給他們的資訊吧。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"먼저 의식이 시작된 순간, 의식의 중심으로부터 이면 세계화가 일어났다.","JPN":"まず、儀式が始まった瞬間、儀式の中心部から裏世界化が引き起こされた。","ENG":"When the ritual began, the Counterside Effect occurred from the center of the ritual.","TWN":"儀式開始的瞬間，從儀式的中心發生異界化。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_SILHOUETTE","text":{"KOREA":"이면 세계화는 황폐해진 사막 도시로 변하며, 보고된 바가 없는 형태다.","JPN":"その詳細は、街を荒廃した砂漠都市へと変容するもので、かつて観測されたことのない特徴である。","ENG":"This kind of Counterside Effect changing the landscape into a devastated desert city has never been reported before.","TWN":"異界化就是變成荒蕪的沙漠城市，這是首次發現的內容。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};